#!/bin/bash
# Builds thorvg (thorvg/thorvg) for $TARGET_PLATFORM. thorvg's official
# build is meson, but we don't need its full surface (no GL/Vulkan
# engines, no JPG/PNG/WEBP loaders, no examples, no tests). Compiling
# the few needed source globs directly mirrors what the previous from-
# source build-tools/cmake/thorvg.cmake did (see git history).
#
# Required env:
#   TARGET_PLATFORM   linux-x86_64 | linux-aarch64 |
#                     macos-arm64 | macos-x86_64 |
#                     android-arm64-v8a | android-x86_64 |
#                     ios-arm64 | ios-x86_64 |
#                     webasm | windows-x86_64
#   OUTPUT_DIR        where the tarball is written
#
# Version is read from this directory's `version` file (upstream tag
# without the leading `v`).
#
# Output tarball layout (consumed by build-tools/cmake/thorvg.cmake):
#   lib/libthorvg.a
#   include/thorvg.h            (and any other top-level headers from inc/)
#   include-internal/common/*.h
#   include-internal/renderer/*.h
#   include-internal/...        (mirrors src/<subdir>/*.h)
#
# WHY include-internal: yetty/src/yetty/ythorvg uses thorvg's internal
# RenderMethod and PAINT() machinery, which lives in src/renderer/ and
# src/common/. We can't drop those — ship the .h files preserving the
# upstream layout so the consumer can wire `-Iinclude-internal/renderer`
# and `-Iinclude-internal/common` to the same effect the from-source
# cmake had.
#
# Feature set baked in (matches the old from-source cmake):
#   THORVG_SW_RASTER_SUPPORT     1
#   THORVG_SVG_LOADER_SUPPORT    1
#   THORVG_LOTTIE_LOADER_SUPPORT 1
# All other engines and loaders are off — keep the static archive small.
#
# Patch: we add sized-delete + nothrow new/delete to tvgInitializer.cpp.
# Same patch the old cmake applied. WHY: thorvg overrides global
# operator new/delete to use its tvg::malloc/free, but the upstream
# version is incomplete (missing C++14 sized delete and nothrow new),
# which causes alloc/dealloc mismatches with litehtml + SPIRV-Tools.

set -Eeuo pipefail
trap 'rc=$?; echo "FAILED: rc=$rc line=$LINENO source=${BASH_SOURCE[0]} cmd: $BASH_COMMAND" >&2' ERR

: "${TARGET_PLATFORM:?TARGET_PLATFORM is required}"
: "${OUTPUT_DIR:?OUTPUT_DIR is required}"

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
VERSION_FILE="$SCRIPT_DIR/version"
[ -f "$VERSION_FILE" ] || { echo "missing $VERSION_FILE" >&2; exit 1; }
VERSION="$(tr -d '[:space:]' < "$VERSION_FILE")"
[ -n "$VERSION" ] || { echo "$VERSION_FILE is empty" >&2; exit 1; }

WORK_DIR="${WORK_DIR:-/tmp/yetty-3rdparty-thorvg-$TARGET_PLATFORM}"
CACHE_DIR="${CACHE_DIR:-$HOME/.cache/yetty-3rdparty}"
NCPU="$(nproc 2>/dev/null || sysctl -n hw.ncpu 2>/dev/null || echo 4)"

THORVG_URL="https://github.com/thorvg/thorvg/archive/refs/tags/v${VERSION}.tar.gz"
THORVG_TARBALL="$CACHE_DIR/thorvg-${VERSION}.tar.gz"
SRC_DIR="$WORK_DIR/thorvg-${VERSION}"
INSTALL_DIR="$WORK_DIR/install-${TARGET_PLATFORM}"
STAGE="$WORK_DIR/stage-${TARGET_PLATFORM}"
TARBALL="$OUTPUT_DIR/thorvg-${TARGET_PLATFORM}-${VERSION}.tar.gz"

mkdir -p "$WORK_DIR" "$OUTPUT_DIR" "$CACHE_DIR"

#-----------------------------------------------------------------------------
# Fetch + extract
#-----------------------------------------------------------------------------
if [ ! -f "$THORVG_TARBALL" ]; then
    _part="$THORVG_TARBALL.part.$$"
    (
        if command -v flock >/dev/null 2>&1; then flock -x 9; fi
        if [ ! -f "$THORVG_TARBALL" ]; then
            echo "==> downloading thorvg ${VERSION}"
            curl -fL --retry 8 --retry-delay 5 --retry-all-errors \
                -o "$_part" "$THORVG_URL"
            mv "$_part" "$THORVG_TARBALL"
        fi
    ) 9>"$CACHE_DIR/.thorvg-download.lock"
    rm -f "$_part"
fi

if [ ! -d "$SRC_DIR" ]; then
    echo "==> extracting -> $SRC_DIR"
    tar -C "$WORK_DIR" -xzf "$THORVG_TARBALL"
fi

rm -rf "$INSTALL_DIR" "$STAGE"
mkdir -p "$INSTALL_DIR/lib" "$INSTALL_DIR/include" "$STAGE"

#-----------------------------------------------------------------------------
# Generate config.h (the same one the old cmake wrote into src/common/)
#-----------------------------------------------------------------------------
cat > "$SRC_DIR/src/common/config.h" <<EOF
// ThorVG Configuration Header — generated by build-tools/3rdparty/thorvg/_build.sh
#ifndef _TVG_CONFIG_H_
#define _TVG_CONFIG_H_

#define THORVG_VERSION_STRING "${VERSION}"

#define THORVG_SW_RASTER_SUPPORT 1

#define THORVG_SVG_LOADER_SUPPORT 1
#define THORVG_LOTTIE_LOADER_SUPPORT 1

#endif // _TVG_CONFIG_H_
EOF

#-----------------------------------------------------------------------------
# Patch tvgInitializer.cpp: add sized-delete + nothrow new/delete.
#
# Upstream defines only `operator new(size_t)` and `operator delete(void*)`.
# C++14 introduced sized delete; consumers that get inlined sized delete
# from libstdc++ will skip thorvg's free, causing alloc/dealloc mismatches
# in this archive. Same goes for nothrow new — SPIRV-Tools uses it heavily.
#
# Implementation: pure-shell append. The added operators have signatures
# that are distinct from upstream's, so appending at end-of-file is
# equivalent to splicing in place — no python3 needed (MSYS2 CLANG64
# doesn't ship it). Idempotent via a grep guard.
#-----------------------------------------------------------------------------
TVG_INIT="$SRC_DIR/src/renderer/tvgInitializer.cpp"
[ -f "$TVG_INIT" ] || { echo "missing $TVG_INIT — upstream layout changed?" >&2; exit 1; }

if grep -q 'operator delete(void\* ptr, std::size_t)' "$TVG_INIT"; then
    echo "tvgInitializer.cpp already patched, skipping" >&2
else
    # Sanity-check the upstream symbol layout we're complementing.
    grep -q 'void operator delete(void\* ptr) noexcept' "$TVG_INIT" || {
        echo "PATCH FAILED: upstream layout in tvgInitializer.cpp changed — \
expected 'void operator delete(void* ptr) noexcept' to be defined" >&2
        exit 1
    }
    cat >> "$TVG_INIT" <<'PATCH_EOF'

// --- yetty 3rdparty patch: complete the global allocator overrides ---
// Upstream defines only operator new(size_t) and operator delete(void*).
// Without sized-delete + nothrow forms, consumers (litehtml, SPIRV-Tools,
// etc.) get alloc/dealloc mismatches when they pick the standard form
// inlined from libstdc++ instead of thorvg's overrides.
void operator delete(void* ptr, std::size_t) noexcept {
    tvg::free(ptr);
}

void* operator new(std::size_t size, const std::nothrow_t&) noexcept {
    return tvg::malloc(size);
}

void operator delete(void* ptr, const std::nothrow_t&) noexcept {
    tvg::free(ptr);
}
PATCH_EOF
    echo "tvgInitializer.cpp patched (sized-delete + nothrow new/delete)" >&2
fi

#-----------------------------------------------------------------------------
# Per-platform compiler.
#-----------------------------------------------------------------------------
CXXFLAGS_BASE="-O2 -fPIC -std=c++17 -DNDEBUG -DTVG_STATIC -w"
CXX=c++
AR=ar
CXXFLAGS_EXTRA=""

case "$TARGET_PLATFORM" in
linux-x86_64) CXX=g++ ;;
linux-aarch64)
    : "${CROSS_PREFIX:=aarch64-unknown-linux-gnu-}"
    CXX="${CROSS_PREFIX}g++"
    AR="${CROSS_PREFIX}ar"
    ;;
macos-x86_64) CXX=clang++; CXXFLAGS_EXTRA="-arch x86_64" ;;
macos-arm64)  CXX=clang++; CXXFLAGS_EXTRA="-arch arm64"  ;;
ios-arm64|ios-x86_64)
    unset DEVELOPER_DIR MACOSX_DEPLOYMENT_TARGET SDKROOT NIX_APPLE_SDK_VERSION
    export PATH="/usr/bin:$PATH"
    : "${IOS_MIN:=15.0}"
    case "$TARGET_PLATFORM" in
        ios-arm64)  _IOS_SDK="iphoneos";        _IOS_ARCH="arm64";  _MIN_FLAG="-miphoneos-version-min=${IOS_MIN}" ;;
        ios-x86_64) _IOS_SDK="iphonesimulator"; _IOS_ARCH="x86_64"; _MIN_FLAG="-mios-simulator-version-min=${IOS_MIN}" ;;
    esac
    _IOS_SYSROOT="$(/usr/bin/xcrun --sdk "$_IOS_SDK" --show-sdk-path)"
    [ -d "$_IOS_SYSROOT" ] || { echo "missing iOS SDK: $_IOS_SYSROOT" >&2; exit 1; }
    CXX="/usr/bin/clang++"
    AR="/usr/bin/ar"
    CXXFLAGS_EXTRA="-arch $_IOS_ARCH -isysroot $_IOS_SYSROOT $_MIN_FLAG"
    ;;
android-arm64-v8a|android-x86_64)
    : "${ANDROID_NDK_HOME:?ANDROID_NDK_HOME not set — source the .#3rdparty-${TARGET_PLATFORM} shell}"
    : "${ANDROID_API:=26}"
    case "$TARGET_PLATFORM" in
        android-arm64-v8a) _NDK_TRIPLE="aarch64-linux-android" ;;
        android-x86_64)    _NDK_TRIPLE="x86_64-linux-android"  ;;
    esac
    CXX="${_NDK_TRIPLE}${ANDROID_API}-clang++"
    AR="llvm-ar"
    command -v "$CXX" >/dev/null 2>&1 || { echo "error: $CXX not on PATH" >&2; exit 1; }
    ;;
webasm)
    command -v em++ >/dev/null 2>&1 || { echo "error: em++ not found" >&2; exit 1; }
    CXX=em++
    AR=emar
    ;;
windows-x86_64)
    if [ "${MSYSTEM:-}" != "CLANG64" ]; then
        echo "error: windows-x86_64 must run inside MSYS2 CLANG64 (MSYSTEM=$MSYSTEM)" >&2
        exit 1
    fi
    CXX=clang++
    AR=llvm-ar
    CXXFLAGS_EXTRA="-DNOMINMAX -DWIN32_LEAN_AND_MEAN"
    ;;
*) echo "unknown TARGET_PLATFORM: $TARGET_PLATFORM" >&2; exit 1 ;;
esac

CXXFLAGS="$CXXFLAGS_BASE $CXXFLAGS_EXTRA"

#-----------------------------------------------------------------------------
# Collect sources (matches the file(GLOB ...) calls in the old cmake).
#
# Globbing here is OK — thorvg's directory layout is part of its public
# release artifact and only the loaders/engines we don't enable are
# absent (those just produce no globs and therefore nothing to compile).
#-----------------------------------------------------------------------------
SRC_GROUPS=(
    "$SRC_DIR/src/common"
    "$SRC_DIR/src/renderer"
    "$SRC_DIR/src/renderer/sw_engine"
    "$SRC_DIR/src/loaders/svg"
    "$SRC_DIR/src/loaders/lottie"
    "$SRC_DIR/src/loaders/raw"
)

# Build the include path the same way the old cmake's PRIVATE list did.
INCS=(
    "-I$SRC_DIR/inc"
    "-I$SRC_DIR/src/common"
    "-I$SRC_DIR/src/renderer"
    "-I$SRC_DIR/src/renderer/sw_engine"
    "-I$SRC_DIR/src/loaders/svg"
    "-I$SRC_DIR/src/loaders/lottie"
    "-I$SRC_DIR/src/loaders/raw"
)

SOURCES=()
for _grp in "${SRC_GROUPS[@]}"; do
    [ -d "$_grp" ] || { echo "missing source group $_grp — upstream layout changed?" >&2; exit 1; }
    while IFS= read -r -d '' _f; do
        SOURCES+=("$_f")
    done < <(find "$_grp" -maxdepth 1 -name '*.cpp' -print0 | sort -z)
done

[ "${#SOURCES[@]}" -gt 0 ] || { echo "no source files found" >&2; exit 1; }
echo "==> compiling thorvg ${VERSION} for $TARGET_PLATFORM (${#SOURCES[@]} .cpp files)"

#-----------------------------------------------------------------------------
# Compile in parallel + archive
#-----------------------------------------------------------------------------
mkdir -p "$WORK_DIR/obj"
OBJS=()
PIDS=()
JOBS=0
for _src in "${SOURCES[@]}"; do
    # Object name uses sha-of-path to dedupe identically-named files
    # across the loader subdirs (svg/tvgSvgLoader.cpp vs lottie/...).
    _hash="$(printf '%s' "$_src" | cksum | awk '{print $1}')"
    _base="$(basename "${_src%.cpp}")"
    _obj="$WORK_DIR/obj/${_base}-${_hash}.o"
    OBJS+=("$_obj")

    (
        $CXX $CXXFLAGS "${INCS[@]}" -c "$_src" -o "$_obj"
    ) &
    PIDS+=($!)
    JOBS=$((JOBS+1))
    if [ "$JOBS" -ge "$NCPU" ]; then
        wait "${PIDS[0]}"
        PIDS=("${PIDS[@]:1}")
        JOBS=$((JOBS-1))
    fi
done
for pid in "${PIDS[@]}"; do wait "$pid"; done

$AR rcs "$INSTALL_DIR/lib/libthorvg.a" "${OBJS[@]}"

#-----------------------------------------------------------------------------
# Stage public headers (whatever upstream ships under inc/)
#-----------------------------------------------------------------------------
[ -f "$SRC_DIR/inc/thorvg.h" ] || { echo "missing thorvg.h" >&2; exit 1; }
shopt -s nullglob
for _h in "$SRC_DIR"/inc/*.h; do
    cp "$_h" "$INSTALL_DIR/include/"
done
shopt -u nullglob

#-----------------------------------------------------------------------------
# Stage internal headers (RenderMethod, PAINT() macro, etc.) preserving
# the upstream src/<subdir>/*.h layout under include-internal/.
#-----------------------------------------------------------------------------
mkdir -p "$INSTALL_DIR/include-internal"
# rsync isn't always present in the nix shells — use cp + find.
(
    cd "$SRC_DIR/src"
    while IFS= read -r -d '' _h; do
        _rel="${_h#./}"
        _dst="$INSTALL_DIR/include-internal/$_rel"
        mkdir -p "$(dirname "$_dst")"
        cp "$_h" "$_dst"
    done < <(find . -name '*.h' -print0)
)
# Also include the generated src/common/config.h so the internal headers
# that #include "config.h" resolve.
[ -f "$INSTALL_DIR/include-internal/common/config.h" ] || \
    cp "$SRC_DIR/src/common/config.h" "$INSTALL_DIR/include-internal/common/config.h"

#-----------------------------------------------------------------------------
# Stage + verify
#-----------------------------------------------------------------------------
cp -a "$INSTALL_DIR/lib"              "$STAGE/"
cp -a "$INSTALL_DIR/include"          "$STAGE/"
cp -a "$INSTALL_DIR/include-internal" "$STAGE/"

[ -f "$STAGE/lib/libthorvg.a" ]                        || { echo "missing libthorvg.a"            >&2; exit 1; }
[ -f "$STAGE/include/thorvg.h" ]                       || { echo "missing thorvg.h"               >&2; exit 1; }
[ -d "$STAGE/include-internal/renderer" ]              || { echo "missing include-internal/renderer" >&2; exit 1; }
[ -d "$STAGE/include-internal/common" ]                || { echo "missing include-internal/common"   >&2; exit 1; }

echo "==> packaging -> $TARBALL"
tar -C "$STAGE" -czf "$TARBALL" .

echo ""
echo "thorvg ${VERSION} ($TARGET_PLATFORM) ready:"
ls -lh "$TARBALL"
tar -tzf "$TARBALL"
